import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input from a form field
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Escaping user input before displaying it on the webpage
        String escapedUserInput = Encode.forHtml(userInput);

        // Displaying the properly escaped user input on a webpage
        System.out.println("<div>" + escapedUserInput + "</div>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
